LoadWWPContext.Call(&Context) &EmpCod = &Context.EmpCod &FilCod = &Context.FilCod RetornaConfSistema.Call(&Context.EmpCod, &Context.FilCod, domConfSistema.TCon009_FecharComEstoque, &TCon009_FecharComEstoque) RetornaConfSistema.Call(&Context.EmpCod, &Context.FilCod, domConfSistema.TCon010_LiberarCreditoPedido, &LiberaCreditoPedido)
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&EmpCod.Visible = False
