JSDynamicFilters.Caption = '' &DynamicFiltersSelector1 = !'LCTCOD' Do 'EnableDynamicFilters1' &DynamicFiltersSelector2 = !'LCTCOD' Do 'EnableDynamicFilters2' &DynamicFiltersSelector3 = !'LCTCOD' Do 'EnableDynamicFilters3'
AddDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 2, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) AddDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters3.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) &PedSts = Status_Pedido.ABERTO &PedStsEmb = nullvalue(&PedStsEmb) &PedBlq = nullvalue(&PedBlq) DDO_Grid.GridInternalName = Grid.InternalName Form.Caption = 'Monitora Embalo Pedidos'
Do 'PrepareTransaction' Do 'LoadGridState' If &OrderedBy < 1 &OrderedBy = 1 Do 'SetDDOSortedStatus' EndIf &DDO_TitleSettingsIcons = GetWWPTitleSettingsIcons() GridPaginationBar.RowsPerPageSelectedValue = Grid.Rows
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
If &PedDtaEms_To.IsEmpty() and &PedDtaEms.IsEmpty() &PedDtaEms_To = serverdate() &PedDtaEms = &PedDtaEms_To - 30 EndIF
EndEvent
