Event Grid.Load
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&OqueFazer.Clear() &OqueFazer.AddItem(0, '-O que Fazer?-') If (&VENDAFECHAESTOQUEAutNiv > 0 and (PedSts = Status_Pedido.ABERTO) and (LctAtuEst = Status_EntradaSaida.Saida)) &OqueFazer.AddItem(1, 'Alterar status: SEPARAÇÃO') Endif If (PedSts <> Status_Pedido.ABERTO and &VENDAABREESTOQUEAutNiv > 0) &OqueFazer.AddItem(2, 'Abrir Estoque') Endif &OqueFazer.AddItem(3, 'Impressão Separação') &OqueFazer.AddItem(4, 'Remover Embalo/Embalado')
&gridPedCliCodRaz = PedCliCodRaz &NovoStatusFinanceiro = trim(PedNovStsFinNom)
Do Case Case PedStsEmb = Status_embalo.EMBALADO &Embalo.ColumnClass = !'WWColumn WWColumnSuccess WWColumnSuccessSingleCell' Case PedStsEmb <> Status_embalo.EMBALADO &Embalo.ColumnClass = !'WWColumn WWColumnBold WWColumnBoldSingleCell' Otherwise &Embalo.ColumnClass = 'WWColumn' EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
prcStatusPedidoRGB.Call(EmpCod, PedNovStsFinNom, &R, &G, &B ) &NovoStatusFinanceiro.ForeColor = RGB(&R, &G, &B)
&NovoStatus = trim(PedNovStsNom) prcStatusPedidoRGB.Call(EmpCod, PedNovStsNom, &R, &G, &B ) &NovoStatus.ForeColor = RGB(&R, &G, &B)
&Embalo = trim(DtoC(PedDtaEmba)) + ' ' + trim(PedHorEmb)
&Mensagem = trim(str(PedTraSaiCod)) + ' - ' + trim(PedTraSaiRaz) &PedTraRaz = Substr(&Mensagem, 1, 40)
&Volumes = trim(str(PedQtdVol)) + ' '+ trim(PedEspVol)
EndEvent
