/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'DoEmbalando'
&sdtPedidos.Clear()
For Each line in grid If &IsSeleciona = true &sdtPedidosItem = new() &sdtPedidosItem.EmPCod = EmpCod &sdtPedidosItem.FiLCod = FilCod &sdtPedidosItem.PedCod = PedCod &sdtPedidosItem.PedCliCodRaz = PedCliCodRaz &sdtPedidos.Add(&sdtPedidosItem) EndIF EndFor
if &sdtPedidos.Count > 0 &WebSession.Set('wpEmbalar', &sdtPedidos.ToXml())
wpEmbalandoPedido.Popup()
Refresh Else msg('Nenhum Pedido selecionado para ser Embalado!') EndIf
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'DoDespachar'
&sdtPedidos.Clear()
For Each line in grid If &IsSeleciona = true &sdtPedidosItem = new() &sdtPedidosItem.EmPCod = EmpCod &sdtPedidosItem.FiLCod = FilCod &sdtPedidosItem.PedCod = PedCod &sdtPedidosItem.PedCliCodRaz = PedCliCodRaz &sdtPedidos.Add(&sdtPedidosItem) EndIF EndFor
if &sdtPedidos.Count > 0 &WebSession.Set('wpEmbalar', &sdtPedidos.ToXml())
wpEmbaladoPedido.Popup()
Refresh Else msg('Nenhum Pedido selecionado para finalizar Embalo!') EndIf
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
