Sub 'Do AlterarpedidoSeparando'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&EmpCod_Selected = EmpCod &FilCod_Selected = FilCod &PedCod_Selected = PedCod DVelop_ConfirmPanel_AlterarpedidoSeparando.Confirm()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'Do Action AlterarpedidoSeparando'
&IsClienteComCredito = true
if &LiberaCreditoPedido = 'S' or &LiberaCreditoPedido = 'X' &IsPodeFaturar = RetornaIsPodeFaturar.Udp(EmpCod, FilCod, PedCod) //TESTA SE VENCEU ALGUMA DUPLICATA APOS A LIBERACAO DO CREDITO prcDuplicataVencida.Call(EmpCod, PedCliCod, &CreDtaVct) if &CreDtaVct > PedDtaCrd and not &CreDtaVct.IsEmpty() and not PedDtaCrd.IsEmpty() and not PedDtaCrd.IsNull() &IsPodeFaturar = false Endif EndIF
VerificaLoteInformadoPedidoCompra.Call(EmpCod, FilCod, PedCod, &IsTodosInformados, &Mensagem)
Do Case Case &IsTodosInformados <> true wpinformalotesfaltantespedidoVenda.Link('WWPEDIDOEMBALADO', EmpCod, FilCod, PedCod)
Case LctAtuEst <> Status_EntradaSaida.Saida //SOMENTE ATUALIZA ESTOQUE SAIDA msg('Opção não disponível para operações que NÃO atualizam o estoque!')
Case PedSts <> Status_Pedido.ABERTO //STATUS NAO ABERTO msg('Opção disponível apenas para pedidos com status ABERTO!')
Case (&LiberaCreditoPedido = 'S' or &LiberaCreditoPedido = 'X') and &IsPodeFaturar = false if &CreDtaVct > PedDtaCrd and not &CreDtaVct.IsEmpty() msg('Pedido com DUPLICATAS VENCIDA, Apos liberação do Crédito, Nova liberação Requerida!') Else msg('Pedido não liberado para Faturamento! Falta Liberação do Crédito!') Endif
Case &IsClienteComCredito = false msg('Crédito do cliente atingido, Solicite liberação de limite crédito para o pedido! [CONF210]')
Otherwise &IsProdutoEmBalanco = VerificaProdutoEmBalanco.Udp(EmpCod, FilCod, PedCod)
If &IsProdutoEmBalanco = true MSG('Pedido este pedido não pode ser Liberado para "SEPARAR", porque têm Itens em Balanço!') Else
&IsSemEstoque = false //if &LiberarEstoqueAjustarPedido = 'S' and &TCon009_FecharComEstoque = 'S' if &TCon009_FecharComEstoque = 'S' &IsSemEstoque = VerificaProdutoSemEstoque.Udp(&EmpCod_Selected, &FilCod_Selected, &PedCod_Selected) Endif
If &IsSemEstoque = true msg('No pedido existe produtos que não possuem estoque suficiente! [TCon009_FecharComEstoque]') Else //ajusta estoque LiberarEstoquePedido.Call(&EmpCod_Selected, &FilCod_Selected, &PedCod_Selected, &Context.PesCod, 'S') msg('Pedido Alterado para SEPARANDO!') Refresh Endif EndIf EndCAse
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'Do AbrirEstoquePedido'
If PedSts <> Status_Pedido.ABERTO &VENDAABREESTOQUEAutNiv = RetornaAutorizacao.UDP('VENDAABREESTOQUE', Status_SimNao.Nao, 1)
If &VENDAABREESTOQUEAutNiv > 0
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
AbrirEstoquePedido_Modal.Confirm()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Else msg('Não Autorizado ao Nível de Abrir Estoque Pedido Venda. [VENDAABREESTOQUE]') EndIF Else msg('Opção Disponível somente pedido diferentes de Abertos!') EndiF
EndSub
Sub 'Do Imprimir'
&NomeArquivo = 'PedidoSeparacao' + trim(str(PedCod)) RCOOpenWindow1.LinkOpen = RELJAS029.Link(EmpCod, FilCod, PedCod, &Context.PesCod, &NomeArquivo, 'S', &Varchar,false,false) RCOOpenWindow1.OpenWindow(True, 500, 500, True, 0, 0, False)
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'Do ActionRemoveDespacho'
RetornaAutorizacao.Call('WWPEDIDOVENDAEMBALO', Status_SimNao.Nao, 3, &AutNiv) If &AutNiv < 3 msg('Não autorizado ao Level 3 do Monitora Embalo de Pedidos!') Else
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&EmpCod_Selected = EmpCod &FilCod_Selected = FilCod &PedCod_Selected = PedCod DVelop_ConfirmPanel_ActionRemoveDespacho.Confirm()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Endif
EndSub
Sub 'Do Action ActionRemoveDespacho'
&auxPedDtaDsp.SetEmpty() &auxPedHorDsp.SetEmpty() GravaDataEmbalado.Call('DEL',&EmpCod_Selected, &FilCod_Selected, &PedCod_Selected, 0, 0, &auxPedDtaDsp, '', &auxPedHorDsp, &Context.PesCod, &Context.UserName) Refresh
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
if 1=2
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(&PgmName + !"GridState") = !"" &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState")) Else &GridState.FromXml(&Session.Get(&PgmName + !"GridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc Do 'SetDDOSortedStatus'
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PEDCOD" &PedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTS" &PedSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLICOD" &PedCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTSEMB" &PedStsEmb.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDTRASAICOD" &PedTraSaiCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDTRASAIRAZ" &PedTraSaiRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDNOVSTSFINNOM" &PedNovStsFinNom.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDDTAEMS" &PedDtaEms.FromString(&GridStateFilterValue.Value) &PedDtaEms_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"LCTTIP" &LctTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"LCTATUSAL" &LctAtuSal.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDBLQ" &PedBlq.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) EndCase EndFor Do 'LoadDynFiltersState' If not &GridState.PageSize.Trim().IsEmpty() Grid.Rows = &GridState.PageSize.ToNumeric() EndIf Grid.CurrentPage = &GridState.CurrentPage
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Else // Load grid state from session. If &Session.Get(&PgmName + !"GridState") = !"" &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState")) Else &GridState.FromXml(&Session.Get(&PgmName + !"GridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc Do 'SetDDOSortedStatus'
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PEDCOD" &PedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLICOD" &PedCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTSEMB" &PedStsEmb.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDTRASAICOD" &PedTraSaiCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDTRASAIRAZ" &PedTraSaiRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDDTAEMS" &PedDtaEms.FromString(&GridStateFilterValue.Value) &PedDtaEms_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor Do 'LoadDynFiltersState' If not &GridState.PageSize.Trim().IsEmpty() Grid.Rows = &GridState.PageSize.ToNumeric() EndIf Grid.CurrentPage = &GridState.CurrentPage Endif
EndSub
Sub 'LoadDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
